'use client'

import { useState } from 'react'
import Navbar from '@/components/navbar/Navbar'
import Footer from '@/components/sections/Footer'

export default function ConsultancyPage() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    projectType: '',
    budget: '',
    message: ''
  })

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    })
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    alert('Thank you for your inquiry. We will contact you within 48 hours.')
    setFormData({
      name: '',
      email: '',
      phone: '',
      projectType: '',
      budget: '',
      message: ''
    })
  }

  return (
    <>
      <Navbar />
      <main className="pt-32 pb-16 px-8 bg-branco min-h-screen">
        <div className="max-w-[900px] mx-auto">
          <h1 className="font-display text-preto text-center mb-6" style={{ fontSize: 'clamp(3rem, 6vw, 5rem)' }}>
            Book a Consultation
          </h1>
          <p className="text-center text-cinza text-lg mb-16 max-w-[600px] mx-auto">
            Share your vision with us. We'll discuss how Babel Designs can bring your space to life.
          </p>

          <form onSubmit={handleSubmit} className="bg-branco border border-preto/10 p-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
              {/* Name */}
              <div>
                <label htmlFor="name" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                  Full Name
                </label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors"
                />
              </div>

              {/* Email */}
              <div>
                <label htmlFor="email" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                  Email Address
                </label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors"
                />
              </div>

              {/* Phone */}
              <div>
                <label htmlFor="phone" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                  Phone Number
                </label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors"
                />
              </div>

              {/* Project Type */}
              <div>
                <label htmlFor="projectType" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                  Project Type
                </label>
                <select
                  id="projectType"
                  name="projectType"
                  value={formData.projectType}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors"
                >
                  <option value="">Select...</option>
                  <option value="residential">Residential Interior</option>
                  <option value="commercial">Commercial Space</option>
                  <option value="furniture">Custom Furniture</option>
                  <option value="consultation">Design Consultation</option>
                </select>
              </div>
            </div>

            {/* Budget */}
            <div className="mb-8">
              <label htmlFor="budget" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                Estimated Budget
              </label>
              <select
                id="budget"
                name="budget"
                value={formData.budget}
                onChange={handleChange}
                required
                className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors"
              >
                <option value="">Select range...</option>
                <option value="50k-100k">$50,000 - $100,000</option>
                <option value="100k-250k">$100,000 - $250,000</option>
                <option value="250k-500k">$250,000 - $500,000</option>
                <option value="500k+">$500,000+</option>
              </select>
            </div>

            {/* Message */}
            <div className="mb-8">
              <label htmlFor="message" className="block text-cinza text-xs tracking-wider uppercase mb-2">
                Project Description
              </label>
              <textarea
                id="message"
                name="message"
                value={formData.message}
                onChange={handleChange}
                required
                rows={6}
                placeholder="Tell us about your vision, constraints, and what you hope to achieve..."
                className="w-full px-4 py-3 bg-white border border-preto/20 text-preto focus:outline-none focus:border-cinza transition-colors resize-vertical"
              />
            </div>

            {/* Submit */}
            <button
              type="submit"
              className="w-full py-5 bg-cinza text-branco border-2 border-cinza text-sm tracking-[0.2em] uppercase font-medium hover:bg-transparent hover:text-cinza transition-all duration-400 hover:-translate-y-1"
            >
              Submit Inquiry
            </button>
          </form>
        </div>
      </main>
      <Footer />
    </>
  )
}